import{J as e,n as t,q as n}from"./chunks/runtime-core.esm-bundler.DjYjnAiy.js";import{b as r}from"./chunks/plugin-vue_export-helper.CHY-GVFk.js";const i=JSON.parse(`{"title":"插件概述 - ElysiaJS","description":"Elysia 旨在实现模块化和轻量化，这就是为什么 Elysia 包含了涉及常见模式的预构建插件，以方便开发者使用。Elysia 通过社区插件进一步增强，使其更加个性化。","frontmatter":{"title":"插件概述 - ElysiaJS","head":[["meta",{"property":"og:title","content":"Swagger 插件 - ElysiaJS"}],["meta",{"name":"description","content":"Elysia 旨在实现模块化和轻量化，这就是为什么 Elysia 包含了涉及常见模式的预构建插件，以方便开发者使用。Elysia 通过社区插件进一步增强，使其更加个性化。"}],["meta",{"name":"og:description","content":"Elysia 旨在实现模块化和轻量化，这就是为什么 Elysia 包含了涉及常见模式的预构建插件，以方便开发者使用。Elysia 通过社区插件进一步增强，使其更加个性化。"}]]},"headers":[],"relativePath":"plugins/overview.md","filePath":"plugins/overview.md","lastUpdated":1754230878000}`),a={name:`plugins/overview.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /plugins/overview.md for this page in Markdown format</div><h1 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h1><p>Elysia 旨在实现模块化和轻量化。</p><p>遵循与 Arch Linux 相同的理念（顺便说一句，我使用 Arch）：</p><blockquote><p>设计决策通过开发者共识逐案作出</p></blockquote><p>这确保了开发者最终得到他们所希望创建的高性能 Web 服务器。由此，Elysia 包含了预构建的常见模式插件，以方便开发者使用：</p><h2 id="官方插件" tabindex="-1">官方插件： <a class="header-anchor" href="#官方插件" aria-label="Permalink to “官方插件：”">​</a></h2><ul><li><a href="/plugins/bearer.html">Bearer</a> - 自动检索 <a href="https://swagger.io/docs/specification/authentication/bearer-authentication/" target="_blank" rel="noreferrer">Bearer</a> 令牌</li><li><a href="/plugins/cors.html">CORS</a> - 设置 <a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/CORS" target="_blank" rel="noreferrer">跨来源资源共享 (CORS)</a></li><li><a href="/plugins/cron.html">Cron</a> - 设置 <a href="https://en.wikipedia.org/wiki/Cron" target="_blank" rel="noreferrer">cron</a> 任务</li><li><a href="/eden/overview.html">Eden</a> - Elysia 的端到端类型安全客户端</li><li><a href="/plugins/graphql-apollo.html">GraphQL Apollo</a> - 在 Elysia 上运行 <a href="https://www.apollographql.com/" target="_blank" rel="noreferrer">Apollo GraphQL</a></li><li><a href="/plugins/graphql-yoga.html">GraphQL Yoga</a> - 在 Elysia 上运行 <a href="https://github.com/dotansimha/graphql-yoga" target="_blank" rel="noreferrer">GraphQL Yoga</a></li><li><a href="/plugins/html.html">HTML</a> - 处理 HTML 响应</li><li><a href="/plugins/jwt.html">JWT</a> - 使用 <a href="https://jwt.io/" target="_blank" rel="noreferrer">JWT</a> 进行身份验证</li><li><a href="/plugins/opentelemetry.html">OpenTelemetry</a> - 添加对 OpenTelemetry 的支持</li><li><a href="/plugins/server-timing.html">Server Timing</a> - 通过 <a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/Headers/Server-Timing" target="_blank" rel="noreferrer">Server-Timing API</a> 审核性能瓶颈</li><li><a href="/plugins/static.html">Static</a> - 服务静态文件/文件夹</li><li><a href="/plugins/stream.html">Stream</a> - 集成响应流和 <a href="https://developer.mozilla.org/en-US/docs/Web/API/Server-sent_events" target="_blank" rel="noreferrer">服务器发送事件 (SSE)</a></li><li><a href="/plugins/swagger.html">Swagger</a> - 生成 <a href="https://swagger.io/" target="_blank" rel="noreferrer">Swagger</a> 文档</li><li><a href="/plugins/trpc.html">tRPC</a> - 支持 <a href="https://trpc.io/" target="_blank" rel="noreferrer">tRPC</a></li><li><a href="/patterns/websocket.html">WebSocket</a> - 支持 <a href="https://developer.mozilla.org/en-US/docs/Web/API/WebSocket" target="_blank" rel="noreferrer">WebSockets</a></li></ul><h2 id="社区插件" tabindex="-1">社区插件： <a class="header-anchor" href="#社区插件" aria-label="Permalink to “社区插件：”">​</a></h2><ul><li><a href="https://github.com/nikiskaarup/bunsai2" target="_blank" rel="noreferrer">BunSai</a> - 一个全栈无关的 Web 框架，基于 Bun 和 Elysia 构建</li><li><a href="https://github.com/kravetsone/create-elysiajs" target="_blank" rel="noreferrer">Create ElysiaJS</a> - 为您的 Elysia 项目搭建开发环境，以便于（提供 ORM、代码风格检查工具和插件的帮助）！</li><li><a href="https://github.com/pilcrowOnPaper/lucia" target="_blank" rel="noreferrer">Lucia Auth</a> - 身份验证，简单而干净</li><li><a href="https://github.com/wobsoriano/elysia-clerk" target="_blank" rel="noreferrer">Elysia Clerk</a> - 非官方的 Clerk 身份验证插件</li><li><a href="https://github.com/bogeychan/elysia-polyfills" target="_blank" rel="noreferrer">Elysia Polyfills</a> - 在 Node.js 和 Deno 上运行 Elysia 生态系统</li><li><a href="https://github.com/kravetsone/elysia-vite-server" target="_blank" rel="noreferrer">Vite server</a> - 插件，用于在 <code>development</code> 模式下启动和装饰 <a href="https://vitejs.dev/" target="_blank" rel="noreferrer"><code>vite</code></a> 开发服务器，并在 <code>production</code> 模式下提供静态服务（如果需要）</li><li><a href="https://github.com/timnghg/elysia-vite" target="_blank" rel="noreferrer">Vite</a> - 提供带有 Vite 脚本注入的入口 HTML 文件</li><li><a href="https://github.com/trylovetom/elysiajs-nuxt" target="_blank" rel="noreferrer">Nuxt</a> - 将 elysia 与 nuxt 轻松集成！</li><li><a href="https://github.com/kravetsone/elysia-remix" target="_blank" rel="noreferrer">Remix</a> - 使用支持 <code>HMR</code> 的 <a href="https://remix.run/" target="_blank" rel="noreferrer">Remix</a>！（由 <a href="https://vitejs.dev/" target="_blank" rel="noreferrer"><code>vite</code></a> 提供支持）！ 关闭一个长期存在的插件请求 <a href="https://github.com/elysiajs/elysia/issues/12" target="_blank" rel="noreferrer">#12</a></li><li><a href="https://github.com/johnny-woodtke/elysiajs-sync" target="_blank" rel="noreferrer">Sync</a> - 一个轻量级的离线优先数据同步框架，基于 <a href="https://dexie.org/" target="_blank" rel="noreferrer">Dexie.js</a></li><li><a href="https://github.com/kravetsone/elysia-connect-middleware" target="_blank" rel="noreferrer">Connect middleware</a> - 插件，允许您在 Elysia 中直接使用 <a href="https://www.npmjs.com/package/express" target="_blank" rel="noreferrer"><code>express</code></a>/<a href="https://www.npmjs.com/package/connect" target="_blank" rel="noreferrer"><code>connect</code></a> 中间件！</li><li><a href="https://github.com/DevTobias/elysia-helmet" target="_blank" rel="noreferrer">Elysia Helmet</a> - 通过各种 HTTP 头保护 Elysia 应用</li><li><a href="https://github.com/timnghg/elysia-vite-plugin-ssr" target="_blank" rel="noreferrer">Vite Plugin SSR</a> - 使用 Elysia 服务器的 Vite SSR 插件</li><li><a href="https://github.com/kravetsone/elysia-oauth2" target="_blank" rel="noreferrer">OAuth 2.0</a> - 一个用于 <a href="https://en.wikipedia.org/wiki/OAuth" target="_blank" rel="noreferrer">OAuth 2.0</a> 授权流程的插件，支持超过 <strong>42</strong> 个提供商，并且具备 <strong>类型安全</strong>！</li><li><a href="https://github.com/bogeychan/elysia-oauth2" target="_blank" rel="noreferrer">OAuth2</a> - 处理 OAuth 2.0 授权码流程</li><li><a href="https://github.com/ap-1/elysia-oauth2-resource-server" target="_blank" rel="noreferrer">OAuth2 Resource Server</a> - 一个用于验证来自 OAuth2 提供者的 JWT 令牌与 JWKS 端点的插件，支持发行者、受众和范围验证。</li><li><a href="https://github.com/macropygia/elysia-openid-client" target="_blank" rel="noreferrer">Elysia OpenID Client</a> - 一个基于 <a href="https://github.com/panva/node-openid-client" target="_blank" rel="noreferrer">openid-client</a> 的 OpenID 客户端</li><li><a href="https://github.com/rayriffy/elysia-rate-limit" target="_blank" rel="noreferrer">Rate Limit</a> - 简单、轻量级的速率限制器</li><li><a href="https://github.com/tristanisham/logysia" target="_blank" rel="noreferrer">Logysia</a> - 经典的日志中间件</li><li><a href="https://github.com/cybercoder-naj/logestic" target="_blank" rel="noreferrer">Logestic</a> - 一个高级且可定制的 ElysiaJS 日志库</li><li><a href="https://github.com/bogeychan/elysia-logger" target="_blank" rel="noreferrer">Logger</a> - 基于 <a href="https://github.com/pinojs/pino" target="_blank" rel="noreferrer">pino</a> 的日志中间件</li><li><a href="https://github.com/eajr/elylog" target="_blank" rel="noreferrer">Elylog</a> - 简单的标准输出日志库，具有一些自定义选项</li><li><a href="https://github.com/0xrasla/logify" target="_blank" rel="noreferrer">Logify for Elysia.js</a> - 一个漂亮、快速且类型安全的 Elysia.js 应用日志中间件</li><li><a href="https://github.com/tanishqmanuja/nice-logger" target="_blank" rel="noreferrer">Nice Logger</a> - 虽然不是最好的，但也是一个相当不错和甜美的 Elysia 日志器。</li><li><a href="https://github.com/johnny-woodtke/elysiajs-sentry" target="_blank" rel="noreferrer">Sentry</a> - 通过这个 <a href="https://docs.sentry.io/" target="_blank" rel="noreferrer">Sentry</a> 插件捕获跟踪信息和错误</li><li><a href="https://github.com/TotalTechGeek/elysia-lambda" target="_blank" rel="noreferrer">Elysia Lambda</a> - 部署到 AWS Lambda</li><li><a href="https://github.com/gaurishhs/elysia-decorators" target="_blank" rel="noreferrer">Decorators</a> - 使用 TypeScript 装饰器</li><li><a href="https://github.com/kravetsone/elysia-autoload" target="_blank" rel="noreferrer">Autoload</a> - 基于目录结构的文件系统路由器，为 <a href="https://elysiajs.com/eden/overview.html" target="_blank" rel="noreferrer">Eden</a> 生成类型，并支持 <a href="https://github.com/kravetsone/elysia-autoload?tab=readme-ov-file#bun-build-usage" target="_blank" rel="noreferrer"><code>Bun.build</code></a></li><li><a href="https://github.com/kravetsone/elysia-msgpack" target="_blank" rel="noreferrer">Msgpack</a> - 允许您处理 <a href="https://msgpack.org" target="_blank" rel="noreferrer">MessagePack</a></li><li><a href="https://github.com/kravetsone/elysia-xml" target="_blank" rel="noreferrer">XML</a> - 允许您处理 XML</li><li><a href="https://github.com/wobsoriano/elysia-autoroutes" target="_blank" rel="noreferrer">Autoroutes</a> - 文件系统路由</li><li><a href="https://github.com/itsyoboieltr/elysia-group-router" target="_blank" rel="noreferrer">Group Router</a> - 基于文件系统和文件夹的分组路由器</li><li><a href="https://github.com/itsyoboieltr/elysia-basic-auth" target="_blank" rel="noreferrer">Basic Auth</a> - 基本 HTTP 身份验证</li><li><a href="https://github.com/bogeychan/elysia-etag" target="_blank" rel="noreferrer">ETag</a> - 自动生成 HTTP <a href="https://developer.mozilla.org/en-US/docs/Web/HTTP/Headers/ETag" target="_blank" rel="noreferrer">ETag</a></li><li><a href="https://github.com/johnny-woodtke/elysiajs-cdn-cache" target="_blank" rel="noreferrer">CDN Cache</a> - Elysia 的 Cache-Control 插件 - 不再手动设置 HTTP 头部</li><li><a href="https://github.com/eelkevdbos/elysia-basic-auth" target="_blank" rel="noreferrer">Basic Auth</a> - 基本 HTTP 身份验证（使用 <code>request</code> 事件）</li><li><a href="https://github.com/eelkevdbos/elysia-i18next" target="_blank" rel="noreferrer">i18n</a> - 基于 <a href="https://www.i18next.com/" target="_blank" rel="noreferrer">i18next</a> 的 <a href="https://developer.mozilla.org/en-US/docs/Mozilla/Add-ons/WebExtensions/API/i18n" target="_blank" rel="noreferrer">i18n</a> 包装</li><li><a href="https://github.com/gtramontina/elysia-requestid" target="_blank" rel="noreferrer">Elysia Request ID</a> - 添加/转发请求 ID（<code>X-Request-ID</code> 或自定义）</li><li><a href="https://github.com/gtramontina/elysia-htmx" target="_blank" rel="noreferrer">Elysia HTMX</a> - <a href="https://htmx.org/" target="_blank" rel="noreferrer">HTMX</a> 的上下文助手</li><li><a href="https://github.com/gtrabanco/elysia-hmr-html" target="_blank" rel="noreferrer">Elysia HMR HTML</a> - 更改目录中的任何文件时重新加载 HTML 文件</li><li><a href="https://github.com/gtrabanco/elysia-inject-html" target="_blank" rel="noreferrer">Elysia Inject HTML</a> - 在 HTML 文件中注入 HTML 代码</li><li><a href="https://github.com/yfrans/elysia-http-error" target="_blank" rel="noreferrer">Elysia HTTP Error</a> - 从 Elysia 处理程序返回 HTTP 错误</li><li><a href="https://github.com/sylvain12/elysia-http-status-code" target="_blank" rel="noreferrer">Elysia Http Status Code</a> - 集成 HTTP 状态码</li><li><a href="https://github.com/gaurishhs/elysia-nocache" target="_blank" rel="noreferrer">NoCache</a> - 禁用缓存</li><li><a href="https://github.com/gtramontina/elysia-tailwind" target="_blank" rel="noreferrer">Elysia Tailwind</a> - 在插件中编译 <a href="https://tailwindcss.com/" target="_blank" rel="noreferrer">Tailwindcss</a>。</li><li><a href="https://github.com/gusb3ll/elysia-compression" target="_blank" rel="noreferrer">Elysia Compression</a> - 压缩响应</li><li><a href="https://github.com/gaurishhs/elysia-ip" target="_blank" rel="noreferrer">Elysia IP</a> - 获取 IP 地址</li><li><a href="https://github.com/myazarc/elysia-oauth2-server" target="_blank" rel="noreferrer">OAuth2 Server</a> - 使用 Elysia 开发 OAuth2 服务器</li><li><a href="https://github.com/gtramontina/elysia-flash-messages" target="_blank" rel="noreferrer">Elysia Flash Messages</a> - 启用闪存消息</li><li><a href="https://github.com/gtramontina/elysia-authkit" target="_blank" rel="noreferrer">Elysia AuthKit</a> - 非官方的 <a href="https://www.authkit.com/" target="_blank" rel="noreferrer">WorkOS&#39; AuthKit</a> 身份验证</li><li><a href="https://github.com/gtramontina/elysia-error-handler" target="_blank" rel="noreferrer">Elysia Error Handler</a> - 简化错误处理</li><li><a href="https://github.com/yolk-oss/elysia-env" target="_blank" rel="noreferrer">Elysia env</a> - 使用 typebox 的类型安全环境变量</li><li><a href="https://github.com/Edsol/elysia-drizzle-schema" target="_blank" rel="noreferrer">Elysia Drizzle Schema</a> - 帮助在 elysia swagger 模型中使用 Drizzle ORM 模式。</li><li><a href="https://github.com/qlaffont/unify-elysia" target="_blank" rel="noreferrer">Unify-Elysia</a> - 统一 Elysia 的错误代码</li><li><a href="https://github.com/qlaffont/unify-elysia-gql" target="_blank" rel="noreferrer">Unify-Elysia-GQL</a> - 统一 Elysia GraphQL 服务器 (Yoga &amp; Apollo) 的错误代码</li><li><a href="https://github.com/qlaffont/elysia-auth-drizzle" target="_blank" rel="noreferrer">Elysia Auth Drizzle</a> - 用于处理 JWT 认证的库（Header/Cookie/QueryParam）。</li><li><a href="https://github.com/qlaffont/graceful-server-elysia" target="_blank" rel="noreferrer">graceful-server-elysia</a> - 灵感来自 <a href="https://github.com/gquittet/graceful-server" target="_blank" rel="noreferrer">graceful-server</a> 的库。</li><li><a href="https://github.com/PunGrumpy/logixlysia" target="_blank" rel="noreferrer">Logixlysia</a> - 一个美观而简单的 ElysiaJS 日志中间件，带有颜色和时间戳。</li><li><a href="https://github.com/vitorpldev/elysia-fault" target="_blank" rel="noreferrer">Elysia Fault</a> - 一个简单且可定制的错误处理间件，可以创建您自己的 HTTP 错误</li><li><a href="https://github.com/vermaysha/elysia-compress" target="_blank" rel="noreferrer">Elysia Compress</a> - 受 <a href="https://github.com/fastify/fastify-compress" target="_blank" rel="noreferrer">@fastify/compress</a> 启发的 ElysiaJS 插件，用于压缩响应</li><li><a href="https://github.com/labzzhq/compressor/" target="_blank" rel="noreferrer">@labzzhq/compressor</a> - 紧凑的辉煌、广泛的结果：适用于 Elysia 和 Bunnyhop 的 HTTP 压缩器，支持 gzip、deflate 和 brotli。</li><li><a href="https://github.com/morigs/elysia-accepts" target="_blank" rel="noreferrer">Elysia Accepts</a> - Elysia 插件，用于解析接受头和内容协商</li><li><a href="https://github.com/chneau/elysia-compression" target="_blank" rel="noreferrer">Elysia Compression</a> - Elysia 插件，用于压缩响应</li><li><a href="https://github.com/chneau/elysia-logger" target="_blank" rel="noreferrer">Elysia Logger</a> - Elysia 插件，用于记录 HTTP 请求和响应，灵感来自 <a href="https://hono.dev/docs/middleware/builtin/logger" target="_blank" rel="noreferrer">hono/logger</a></li><li><a href="https://github.com/jassix/elysia-cqrs" target="_blank" rel="noreferrer">Elysia CQRS</a> - Elysia 插件，用于 CQRS 模式</li><li><a href="https://github.com/mastermakrela/elysia-supabase" target="_blank" rel="noreferrer">Elysia Supabase</a> - 无缝集成 <a href="https://supabase.com/" target="_blank" rel="noreferrer">Supabase</a> 身份验证和数据库功能到 Elysia，使访问经过身份验证的用户数据和 Supabase 客户端实例变得简单，特别适用于 <a href="https://supabase.com/docs/guides/functions" target="_blank" rel="noreferrer">Edge Functions</a>。</li><li><a href="https://www.npmjs.com/package/elysia-xss" target="_blank" rel="noreferrer">Elysia XSS</a> - Elysia.js 的插件，通过清洗请求体数据提供 XSS (跨站脚本) 保护。</li><li><a href="https://www.npmjs.com/package/elysiajs-helmet" target="_blank" rel="noreferrer">Elysiajs Helmet</a> - 一个全面的安全中间件，帮助通过设置各种 HTTP 头来保护 Elysia.js 应用。</li><li><a href="https://github.com/Ateeb-Khan-97/better-elysia" target="_blank" rel="noreferrer">Decorators for Elysia.js</a> - 通过这个小型库无缝开发和集成 API、Websocket 和流媒体 API。</li><li><a href="https://github.com/ilyhalight/elysia-protobuf" target="_blank" rel="noreferrer">Elysia Protobuf</a> - 支持 Elysia 的 protobuf。</li><li><a href="https://github.com/m1handr/elysia-prometheus" target="_blank" rel="noreferrer">Elysia Prometheus</a> - Elysia 插件，用于暴露 Prometheus 的 HTTP 指标。</li><li><a href="https://github.com/rayriffy/elysia-remote-dts" target="_blank" rel="noreferrer">Elysia Remote DTS</a> - 一个为 Eden Treaty 提供远程 .d.ts 类型的插件。</li><li><a href="https://github.com/staciax/elysia-background" target="_blank" rel="noreferrer">Elysia Background</a> - Elysia.js 的后台任务处理插件。</li></ul><h2 id="相关项目" tabindex="-1">相关项目： <a class="header-anchor" href="#相关项目" aria-label="Permalink to “相关项目：”">​</a></h2><ul><li><a href="https://github.com/m1212e/prismabox" target="_blank" rel="noreferrer">prismabox</a> - 基于您的数据库模型生成 typebox 模式的生成器，适用于 elysia</li></ul><hr><p>如果您为 Elysia 编写了一个插件，请随时通过 <strong>点击下面的 <i>在 GitHub 上编辑此页面</i></strong> 将您的插件添加到列表中 👇</p>`,14)])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};